const now = new Date();
const year = now.getFullYear();
const seq = String(Math.floor(Math.random() * 900000) + 100000);
const ticketId = `TKT-${year}-${seq}`;
const name = ($json['Full Name'] || '').toString().trim();
const company = ($json['Company'] || '').toString().trim();
const email = ($json['Email'] || '').toString().trim();
const problem = ($json['Problem Description'] || '').toString().trim();
if (!email || !problem) { throw new Error('Missing required fields: email and problem are required.'); }
return { json: { ticketId, createdAt: now.toISOString(), name, company, email, problem, status: 'New' } };

