const ticket = $('Normalize Classification').first().json;
const kbRows = $input.all().map(i => i.json);

// Resilient column lookup: tolerates casing, surrounding whitespace,
// and header variants like 'Issue ' or 'SOLUTION'.
function pick(row, target) {
  const want = target.toLowerCase().trim();
  for (const key of Object.keys(row)) {
    if (key.toLowerCase().trim() === want) {
      const v = row[key];
      return (v === null || v === undefined) ? '' : String(v).trim();
    }
  }
  return '';
}

const articles = kbRows
  .map(r => ({ issue: pick(r, 'Issue'), solution: pick(r, 'Solution') }))
  .filter(a => a.issue && a.solution);

const kbContext = articles.length
  ? articles.map(a => `- Issue: ${a.issue} | Solution: ${a.solution}`).join('\n')
  : 'No matching knowledge base articles found.';

return [{ json: { ...ticket, kb_context: kbContext, kb_article_count: articles.length } }];

